package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.DmfaBijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl.DmfapplBijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.rszppo.RszppoBijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.service.APKConstant2Service;
import be.schaubroeck.lpb.tools.service.APKConstantService;
import be.schaubroeck.lpb.tools.service.DmfaVerminderingsPercentageService;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.RszConstantOldService;
import be.schaubroeck.lpb.tools.service.RszConstantService;

public class BijdragePercentagesFactoryImp implements BijdragePercentagesFactory {

    private final ConstantManager constantManager;
    private final RszConstantService rszConstantService;
    private final RszConstantOldService rszConstantOldService;
    private final APKConstantService apkConstantService;
    private final APKConstant2Service apkConstant2Service;
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    private final DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService;

    public BijdragePercentagesFactoryImp(ConstantManager constantManager, NlpGlobalService globalService) {
        this.constantManager = constantManager;
        this.rszConstantService = globalService.getRszConstantService();
        this.rszConstantOldService = globalService.getRszConstantOldService();
        this.apkConstantService = globalService.getApkConstantService();
        this.apkConstant2Service = globalService.getApkConstant2Service();
        this.dmfapplBasisBijdrageService = globalService.getDmfapplBasisBijdrageService();
        this.dmfaVerminderingsPercentageService = globalService.getDmfaVerminderingsPercentageService();
    }

    @Override
    public BijdragePercentages create(RekenTijd rekenTijd, RegulManager regulManager) {
        return switch (RkmTijdperk.getTijdperk(rekenTijd)) {
            case RSZPPO -> new RszppoBijdragePercentages(constantManager, regulManager, rszConstantOldService, rekenTijd);
            case DMFAPPL -> new DmfapplBijdragePercentages(constantManager, regulManager, rszConstantService, apkConstantService, dmfapplBasisBijdrageService,
                    dmfaVerminderingsPercentageService, rekenTijd);
            default -> new DmfaBijdragePercentages(constantManager, regulManager, rszConstantService, apkConstant2Service, dmfapplBasisBijdrageService,
                    dmfaVerminderingsPercentageService, rekenTijd);
        };
    }
}
